    // ── Multiple Gather ops produce separate entries ──────────────────

    #[test]
    fn multiple_gather_ops_produce_separate_entries() {
        use super::super::tensor::OnnxTensor;
        let table1 = OnnxTensor::new(
            "table_a".to_string(),
            safetensors::Dtype::F32,
            vec![100, 32],
            prost::bytes::Bytes::new(),
        );
        let table2 = OnnxTensor::new(
            "table_b".to_string(),
            safetensors::Dtype::F32,
            vec![200, 64],
            prost::bytes::Bytes::new(),
        );
        let mut init = HashMap::new();
        init.insert("table_a".to_string(), table1);
        init.insert("table_b".to_string(), table2);
        let onnx = OnnxGraph {
            name: "multi_gather".to_string(),
            doc_string: String::new(),
            nodes: vec![
                OnnxNode {
                    name: "gather_1".to_string(),
                    op_type: "Gather".to_string(),
                    domain: String::new(),
                    inputs: vec!["table_a".to_string(), "idx_a".to_string()],
                    outputs: vec!["out_a".to_string()],
                    attributes: HashMap::new(),
                },
                OnnxNode {
                    name: "gather_2".to_string(),
                    op_type: "Gather".to_string(),
                    domain: String::new(),
                    inputs: vec!["table_b".to_string(), "idx_b".to_string()],
                    outputs: vec!["out_b".to_string()],
                    attributes: HashMap::new(),
                },
            ],
            inputs: vec![
                model::OnnxValueInfo {
                    name: "idx_a".to_string(),
                    value_type: None,
                    doc_string: String::new(),
                    metadata_props: HashMap::new(),
                },
                model::OnnxValueInfo {
                    name: "idx_b".to_string(),
                    value_type: None,
                    doc_string: String::new(),
                    metadata_props: HashMap::new(),
                },
            ],
            outputs: vec![],
            value_info: vec![],
            initializers: init,
            sparse_initializers: vec![],
            quantization_annotation: vec![],
            metadata_props: HashMap::new(),
        };
        let business = BusinessConfig::default();
        let graph = onnx_to_compiler_graph(&onnx, &business, 512).unwrap();
        let gathers: Vec<_> = graph.ops.iter()
            .filter(|op| matches!(op.kind, OpKind::Gather { .. }))
            .collect();
        assert_eq!(gathers.len(), 2, "Should have 2 separate Gather ops");
        // Verify they have different dimensions from different initializers
        let dims: Vec<(usize, usize)> = gathers.iter().map(|op| {
            if let OpKind::Gather { table_rows, embed_dim, .. } = &op.kind {
                (*table_rows, *embed_dim)
            } else {
                unreachable!()
            }
        }).collect();
        assert!(dims.contains(&(100, 32)), "Should have table_a dimensions");
        assert!(dims.contains(&(200, 64)), "Should have table_b dimensions");
    }

