    #[test]
    fn infer_shape_mixed_dims_all_variants() {
        let vi = model::OnnxValueInfo {
            name: "mixed_input".to_string(),
            value_type: Some(types::OnnxType::Tensor(types::OnnxTensorType {
                elem_type: proto::tensor_proto::DataType::Float,
                shape: types::OnnxTensorShape {
                    dims: vec![
                        types::OnnxDim::Param("batch".to_string()),
                        types::OnnxDim::Known(128),
                        types::OnnxDim::Unknown,
                        types::OnnxDim::Known(1),
                    ],
                },
            })),
            doc_string: String::new(),
            metadata_props: HashMap::new(),
        };
        let onnx = OnnxGraph {
            name: "mixed_dims_test".to_string(),
            doc_string: String::new(),
            nodes: vec![],
            inputs: vec![vi],
            outputs: vec![],
            value_info: vec![],
            initializers: HashMap::new(),
            sparse_initializers: vec![],
            quantization_annotation: vec![],
            metadata_props: HashMap::new(),
        };
        let business = BusinessConfig::default();
        let graph = onnx_to_compiler_graph(&onnx, &business, 4096).unwrap();
        let t = graph.tensors.iter().find(|t| t.name == "mixed_input")
            .expect("mixed_input should be registered");
        assert_eq!(t.shape.len(), 4, "Should have 4 dims");
        assert!(
            matches!(&t.shape[0], SymDim::Symbolic { name, max_value: Some(4096) } if name == "batch"),
            "First dim should be Symbolic(batch, 4096)"
        );
        assert!(matches!(&t.shape[1], SymDim::Concrete(128)));
        assert!(
            matches!(&t.shape[2], SymDim::Symbolic { name, max_value: Some(4096) } if name == "unknown"),
            "Unknown dim should become Symbolic(unknown, 4096)"
        );
        assert!(matches!(&t.shape[3], SymDim::Concrete(1)));
    }

