    // ── Chain: Gather → RmsNorm → MatMul ──────────────────────────────

    #[test]
    fn chain_gather_rmsnorm_matmul() {
        use super::super::tensor::OnnxTensor;
        let embed = OnnxTensor::new(
            "emb_w".to_string(),
            safetensors::Dtype::F32,
            vec![100, 64],
            prost::bytes::Bytes::new(),
        );
        let norm_w = OnnxTensor::new(
            "norm_w".to_string(),
            safetensors::Dtype::F32,
            vec![64],
            prost::bytes::Bytes::new(),
        );
        let proj_w = OnnxTensor::new(
            "proj_w".to_string(),
            safetensors::Dtype::F32,
            vec![32, 64],
            prost::bytes::Bytes::new(),
        );
        let mut init = HashMap::new();
        init.insert("emb_w".to_string(), embed);
        init.insert("norm_w".to_string(), norm_w);
        init.insert("proj_w".to_string(), proj_w);
        let onnx = OnnxGraph {
            name: "chain_grm".to_string(),
            doc_string: String::new(),
            nodes: vec![
                OnnxNode {
                    name: "gather".to_string(),
                    op_type: "Gather".to_string(),
                    domain: String::new(),
                    inputs: vec!["emb_w".to_string(), "ids".to_string()],
                    outputs: vec!["h".to_string()],
                    attributes: HashMap::new(),
                },
                OnnxNode {
                    name: "norm".to_string(),
                    op_type: "SimplifiedLayerNormalization".to_string(),
                    domain: String::new(),
                    inputs: vec!["h".to_string(), "norm_w".to_string()],
                    outputs: vec!["hn".to_string()],
                    attributes: HashMap::new(),
                },
                OnnxNode {
                    name: "proj".to_string(),
                    op_type: "MatMul".to_string(),
                    domain: String::new(),
                    inputs: vec!["hn".to_string(), "proj_w".to_string()],
                    outputs: vec!["out".to_string()],
                    attributes: HashMap::new(),
                },
            ],
            inputs: vec![model::OnnxValueInfo {
                name: "ids".to_string(),
                value_type: None,
                doc_string: String::new(),
                metadata_props: HashMap::new(),
            }],
            outputs: vec![],
            value_info: vec![],
            initializers: init,
            sparse_initializers: vec![],
            quantization_annotation: vec![],
            metadata_props: HashMap::new(),
        };
        let business = BusinessConfig::default();
        let graph = onnx_to_compiler_graph(&onnx, &business, 2048).unwrap();
        assert_eq!(graph.ops.len(), 3, "Should have 3 ops: Gather + RmsNorm + Gemm");
        let labels: Vec<&str> = graph.ops.iter().map(|op| op.label.as_str()).collect();
        assert_eq!(labels, &["gather", "norm", "proj"], "Ops should be in chain order");
    }

