    // ── OnnxDim Eq and Hash ──────────────────────────────────────────

    #[test]
    fn onnx_dim_known_eq_hash() {
        use std::collections::HashSet;
        let d1 = types::OnnxDim::Known(42);
        let d2 = types::OnnxDim::Known(42);
        assert_eq!(d1, d2);
        let mut set = HashSet::new();
        set.insert(d1.clone());
        assert!(set.contains(&d2), "Equal OnnxDim values should hash the same");
    }

    #[test]
    fn onnx_dim_param_eq_hash() {
        use std::collections::HashSet;
        let d1 = types::OnnxDim::Param("seq_len".to_string());
        let d2 = types::OnnxDim::Param("seq_len".to_string());
        assert_eq!(d1, d2);
        let mut set = HashSet::new();
        set.insert(d1.clone());
        assert!(set.contains(&d2), "Equal Param dims should hash the same");
    }

    #[test]
    fn onnx_dim_unknown_eq_hash() {
        use std::collections::HashSet;
        assert_eq!(types::OnnxDim::Unknown, types::OnnxDim::Unknown);
        let mut set = HashSet::new();
        set.insert(types::OnnxDim::Unknown);
        assert!(set.contains(&types::OnnxDim::Unknown));
    }

    #[test]
    fn onnx_dim_variants_not_equal() {
        assert_ne!(types::OnnxDim::Known(0), types::OnnxDim::Unknown);
        assert_ne!(types::OnnxDim::Known(0), types::OnnxDim::Param("0".to_string()));
        assert_ne!(types::OnnxDim::Unknown, types::OnnxDim::Param("unknown".to_string()));
    }

