    // ── ConvertError Display idempotency ──────────────────────────────

    #[test]
    fn convert_error_display_idempotent_all_variants() {
        let errors = vec![
            ConvertError::UnsupportedOp {
                op_type: "Conv".to_string(),
                node_name: "n".to_string(),
            },
            ConvertError::MissingInitializer {
                name: "w".to_string(),
                node_name: "n".to_string(),
            },
            ConvertError::InvalidMatMulShape {
                name: "W".to_string(),
                dims: 3,
            },
            ConvertError::NoWeightInput {
                node_name: "mm".to_string(),
            },
            ConvertError::AttributeError {
                node_name: "ln".to_string(),
                reason: "bad".to_string(),
            },
            ConvertError::ShapeInferenceFailed {
                name: "t".to_string(),
                reason: "fail".to_string(),
            },
        ];
        for err in &errors {
            let first = err.to_string();
            let second = err.to_string();
            let third = err.to_string();
            assert_eq!(first, second, "Display should be idempotent (1-2)");
            assert_eq!(second, third, "Display should be idempotent (2-3)");
        }
    }

    // ── Passthrough: Clip then MatMul ─────────────────────────────────

    #[test]
    fn clip_passthrough_then_matmul() {
        use super::super::tensor::OnnxTensor;
        let w = OnnxTensor::new(
            "clip_mm_w".to_string(),
            safetensors::Dtype::F32,
            vec![32, 16],
            prost::bytes::Bytes::new(),
        );
        let mut init = HashMap::new();
        init.insert("clip_mm_w".to_string(), w);
        let onnx = OnnxGraph {
            name: "clip_matmul".to_string(),
            doc_string: String::new(),
            nodes: vec![
                OnnxNode {
                    name: "clip".to_string(),
                    op_type: "Clip".to_string(),
                    domain: String::new(),
                    inputs: vec!["x".to_string()],
                    outputs: vec!["clipped".to_string()],
                    attributes: HashMap::new(),
                },
                OnnxNode {
                    name: "mm".to_string(),
                    op_type: "MatMul".to_string(),
                    domain: String::new(),
                    inputs: vec!["clipped".to_string(), "clip_mm_w".to_string()],
                    outputs: vec!["y".to_string()],
                    attributes: HashMap::new(),
                },
            ],
            inputs: vec![model::OnnxValueInfo {
                name: "x".to_string(),
                value_type: None,
                doc_string: String::new(),
                metadata_props: HashMap::new(),
            }],
            outputs: vec![],
            value_info: vec![],
            initializers: init,
            sparse_initializers: vec![],
            quantization_annotation: vec![],
            metadata_props: HashMap::new(),
        };
        let business = BusinessConfig::default();
        let graph = onnx_to_compiler_graph(&onnx, &business, 512).unwrap();
        // Clip is passthrough (no op added), so only MatMul produces an op
        assert_eq!(graph.ops.len(), 1, "Clip passthrough + MatMul should produce 1 op");
        assert!(matches!(graph.ops[0].kind, OpKind::Gemm { .. }));
    }

