    // ── Binary op with lower rank first input selects higher rank shape

    #[test]
    fn binary_op_broadcasting_lower_rank_first_input() {
        use super::super::tensor::OnnxTensor;
        // bias_vec is 1-D [64], hidden will be 2-D [seq, 64]
        // Put the 1-D tensor first: infer_output_shape_binary should pick hidden's shape
        let bias = OnnxTensor::new(
            "bv".to_string(),
            safetensors::Dtype::F32,
            vec![64],
            prost::bytes::Bytes::new(),
        );
        let embed = OnnxTensor::new(
            "emb".to_string(),
            safetensors::Dtype::F32,
            vec![100, 64],
            prost::bytes::Bytes::new(),
        );
        let mut init = HashMap::new();
        init.insert("bv".to_string(), bias);
        init.insert("emb".to_string(), embed);
        let onnx = OnnxGraph {
            name: "broadcast_order".to_string(),
            doc_string: String::new(),
            nodes: vec![
                OnnxNode {
                    name: "gather".to_string(),
                    op_type: "Gather".to_string(),
                    domain: String::new(),
                    inputs: vec!["emb".to_string(), "ids".to_string()],
                    outputs: vec!["h".to_string()],
                    attributes: HashMap::new(),
                },
                OnnxNode {
                    name: "add_rev".to_string(),
                    op_type: "Add".to_string(),
                    domain: String::new(),
                    // 1-D bias first, 2-D hidden second
                    inputs: vec!["bv".to_string(), "h".to_string()],
                    outputs: vec!["biased".to_string()],
                    attributes: HashMap::new(),
                },
            ],
            inputs: vec![model::OnnxValueInfo {
                name: "ids".to_string(),
                value_type: None,
                doc_string: String::new(),
                metadata_props: HashMap::new(),
            }],
            outputs: vec![],
            value_info: vec![],
            initializers: init,
            sparse_initializers: vec![],
            quantization_annotation: vec![],
            metadata_props: HashMap::new(),
        };
        let business = BusinessConfig::default();
        let graph = onnx_to_compiler_graph(&onnx, &business, 1024).unwrap();
        let biased = graph.tensors.iter().find(|t| t.name == "biased")
            .expect("biased tensor should exist");
        // Output shape should be [seq_len, 64] (from the 2-D input h)
        assert_eq!(biased.shape.len(), 2, "Broadcasting should pick the 2-D shape");
    }

