    // ── OnnxDim hash consistency ────────────────────────────────────────

    #[test]
    fn onnx_dim_hash_consistency() {
        use std::collections::HashSet;
        let d1 = types::OnnxDim::Known(42);
        let d2 = types::OnnxDim::Known(42);
        let mut set = HashSet::new();
        set.insert(d1);
        // Insert d2 should not increase size since they are equal and hash the same
        let before = set.len();
        set.insert(d2);
        assert_eq!(set.len(), before, "Equal dims should produce same hash");
    }

