    // ── OnnxAttributeValue Floats with boundary f32 values ─────────────

    #[test]
    fn onnx_attribute_value_floats_with_nan() {
        let vals = attributes::OnnxAttributeValue::Floats(vec![f32::NAN, f32::INFINITY, f32::NEG_INFINITY]);
        if let attributes::OnnxAttributeValue::Floats(v) = &vals {
            assert!(v[0].is_nan());
            assert!(v[1].is_infinite() && v[1].is_sign_positive());
            assert!(v[2].is_infinite() && v[2].is_sign_negative());
        } else {
            panic!("Expected Floats variant");
        }
    }

    #[test]
    fn onnx_attribute_value_floats_with_zero_and_subnormal() {
        let vals = attributes::OnnxAttributeValue::Floats(vec![0.0, -0.0, f32::MIN_POSITIVE]);
        if let attributes::OnnxAttributeValue::Floats(v) = &vals {
            assert_eq!(v[0], 0.0);
            assert!(v[1].is_sign_negative());
            assert_eq!(v[2], f32::MIN_POSITIVE);
        } else {
            panic!("Expected Floats variant");
        }
    }

