    #[test]
    fn matmul_weight_1x1_succeeds() {
        // Arrange: 1x1 weight matrix
        let onnx = build_graph_with_weight(
            "w",
            vec![1, 1],
            vec![make_node("mm", "MatMul", vec!["x", "w"], vec!["y"])],
            vec![model::OnnxValueInfo {
                name: "x".to_string(),
                value_type: None,
                doc_string: String::new(),
                metadata_props: HashMap::new(),
            }],
            vec![],
        );

        // Act
        let result = onnx_to_compiler_graph(&onnx, &BusinessConfig::default(), 512);

        // Assert: 1x1 is valid 2D
        assert!(result.is_ok());
        let graph = result.unwrap();
        let gemm = graph.ops.iter().find(|op| matches!(op.kind, OpKind::Gemm { .. })).unwrap();
        if let OpKind::Gemm { n, k, .. } = &gemm.kind {
            assert_eq!(*n, 1);
            assert_eq!(*k, 1);
        }
    }

