    // ── OnnxDim: Hash is consistent across invocations ───────────────

    #[test]
    fn onnx_dim_hash_stable_across_invocations() {
        use std::collections::hash_map::DefaultHasher;
        use std::hash::{Hash, Hasher};
        let dim = types::OnnxDim::Known(42);
        let mut h1 = DefaultHasher::new();
        dim.hash(&mut h1);
        let mut h2 = DefaultHasher::new();
        dim.hash(&mut h2);
        assert_eq!(h1.finish(), h2.finish(), "Hash should be deterministic");
    }

