    // ── OnnxTensor scalar_f32 from BF16 dtype ────────────────────────

    #[test]
    fn onnx_tensor_scalar_f32_from_bf16_dtype() {
        // BF16 1.0 is stored as 0x3F80 (upper 16 bits of F32 1.0 = 0x3F800000)
        let bf16_bits: u16 = 0x3F80;
        let bytes = bf16_bits.to_le_bytes().to_vec();
        let t = super::super::tensor::OnnxTensor::new(
            "sf32_bf16".to_string(),
            safetensors::Dtype::BF16,
            vec![],
            bytes.into(),
        );
        let val = t.scalar_f32();
        assert!(val.is_some(), "BF16 scalar_f32 should return Some");
        assert!((val.unwrap() - 1.0f32).abs() < 0.01, "BF16 1.0 should decode to ~1.0");
    }

