    #[test]
    fn graph_matmul_after_passthrough_uses_tensor_id() {
        use super::super::tensor::OnnxTensor;
        let w = OnnxTensor::new(
            "pw".to_string(),
            safetensors::Dtype::F32,
            vec![32, 16],
            prost::bytes::Bytes::new(),
        );
        let mut init = HashMap::new();
        init.insert("pw".to_string(), w);
        let onnx = OnnxGraph {
            name: "pass_then_mm".to_string(),
            doc_string: String::new(),
            nodes: vec![
                OnnxNode {
                    name: "relu1".to_string(),
                    op_type: "Relu".to_string(),
                    domain: String::new(),
                    inputs: vec!["x".to_string()],
                    outputs: vec!["r_out".to_string()],
                    attributes: HashMap::new(),
                },
                OnnxNode {
                    name: "sigmoid1".to_string(),
                    op_type: "Sigmoid".to_string(),
                    domain: String::new(),
                    inputs: vec!["r_out".to_string()],
                    outputs: vec!["s_out".to_string()],
                    attributes: HashMap::new(),
                },
                OnnxNode {
                    name: "mm1".to_string(),
                    op_type: "MatMul".to_string(),
                    domain: String::new(),
                    inputs: vec!["s_out".to_string(), "pw".to_string()],
                    outputs: vec!["y".to_string()],
                    attributes: HashMap::new(),
                },
            ],
            inputs: vec![model::OnnxValueInfo {
                name: "x".to_string(),
                value_type: None,
                doc_string: String::new(),
                metadata_props: HashMap::new(),
            }],
            outputs: vec![model::OnnxValueInfo {
                name: "y".to_string(),
                value_type: None,
                doc_string: String::new(),
                metadata_props: HashMap::new(),
            }],
            value_info: vec![],
            initializers: init,
            sparse_initializers: vec![],
            quantization_annotation: vec![],
            metadata_props: HashMap::new(),
        };
        let business = BusinessConfig::default();
        let graph = onnx_to_compiler_graph(&onnx, &business, 256).unwrap();
        // Only MatMul produces an op; Relu/Sigmoid are passthrough
        assert_eq!(graph.ops.len(), 1, "passthrough + MatMul = 1 op");
        let mm = &graph.ops[0];
        // Input tensor of MatMul should be the original x tensor (passthrough preserves tensor id)
        let x_tensor = graph.tensors.iter().find(|t| t.name == "x").expect("x tensor");
        assert_eq!(mm.inputs[0], x_tensor.id, "MatMul input should be x tensor id (passthrough)");
    }

    #[test]
    fn graph_multiple_outputs_reference_correct_tensors() {
        use super::super::tensor::OnnxTensor;
        let w1 = OnnxTensor::new(
            "w1".to_string(),
            safetensors::Dtype::F32,
            vec![16, 8],
            prost::bytes::Bytes::new(),
        );
        let w2 = OnnxTensor::new(
            "w2".to_string(),
            safetensors::Dtype::F32,
            vec![8, 4],
            prost::bytes::Bytes::new(),
        );
        let mut init = HashMap::new();
        init.insert("w1".to_string(), w1);
        init.insert("w2".to_string(), w2);
        let onnx = OnnxGraph {
            name: "multi_out".to_string(),
            doc_string: String::new(),
            nodes: vec![
                OnnxNode {
                    name: "mm1".to_string(),
                    op_type: "MatMul".to_string(),
                    domain: String::new(),
                    inputs: vec!["x".to_string(), "w1".to_string()],
                    outputs: vec!["a".to_string()],
                    attributes: HashMap::new(),
                },
                OnnxNode {
                    name: "mm2".to_string(),
                    op_type: "MatMul".to_string(),
                    domain: String::new(),
                    inputs: vec!["a".to_string(), "w2".to_string()],
                    outputs: vec!["b".to_string()],
                    attributes: HashMap::new(),
                },
            ],
            inputs: vec![model::OnnxValueInfo {
                name: "x".to_string(),
                value_type: None,
                doc_string: String::new(),
                metadata_props: HashMap::new(),
            }],
            outputs: vec![
                model::OnnxValueInfo {
                    name: "a".to_string(),
                    value_type: None,
                    doc_string: String::new(),
                    metadata_props: HashMap::new(),
                },
                model::OnnxValueInfo {
                    name: "b".to_string(),
                    value_type: None,
                    doc_string: String::new(),
                    metadata_props: HashMap::new(),
                },
            ],
            value_info: vec![],
            initializers: init,
            sparse_initializers: vec![],
            quantization_annotation: vec![],
            metadata_props: HashMap::new(),
        };
        let business = BusinessConfig::default();
        let graph = onnx_to_compiler_graph(&onnx, &business, 256).unwrap();
        assert_eq!(graph.outputs.len(), 2, "should have 2 graph outputs");
        // First output = tensor "a" from mm1
        let a_tensor = graph.tensors.iter().find(|t| t.name == "a").expect("a tensor");
        assert_eq!(graph.outputs[0], a_tensor.id);
        // Second output = tensor "b" from mm2
        let b_tensor = graph.tensors.iter().find(|t| t.name == "b").expect("b tensor");
        assert_eq!(graph.outputs[1], b_tensor.id);
    }

