    #[test]
    fn detect_dtype_bf16_initializer_propagates_to_graph() {
        // Arrange: Graph with BF16 as first initializer
        use super::super::tensor::OnnxTensor;
        let bf16_weight = OnnxTensor::new(
            "first_w".to_string(),
            safetensors::Dtype::BF16,
            vec![32, 16],
            prost::bytes::Bytes::new(),
        );
        let f32_weight = OnnxTensor::new(
            "second_w".to_string(),
            safetensors::Dtype::F32,
            vec![16, 8],
            prost::bytes::Bytes::new(),
        );
        let mut init = HashMap::new();
        // Insert BF16 first, then F32 — detect_dtype uses first value from iterator
        init.insert("first_w".to_string(), bf16_weight);
        init.insert("second_w".to_string(), f32_weight);
        let onnx = OnnxGraph {
            name: "dtype_test".to_string(),
            doc_string: String::new(),
            nodes: vec![OnnxNode {
                name: "mm".to_string(),
                op_type: "MatMul".to_string(),
                domain: String::new(),
                inputs: vec!["x".to_string(), "first_w".to_string()],
                outputs: vec!["y".to_string()],
                attributes: HashMap::new(),
            }],
            inputs: vec![model::OnnxValueInfo {
                name: "x".to_string(),
                value_type: None,
                doc_string: String::new(),
                metadata_props: HashMap::new(),
            }],
            outputs: vec![],
            value_info: vec![],
            initializers: init,
            sparse_initializers: vec![],
            quantization_annotation: vec![],
            metadata_props: HashMap::new(),
        };
        // Act
        let graph = onnx_to_compiler_graph(&onnx, &BusinessConfig::default(), 512).unwrap();
        // Assert: The detected dtype should be derived from the first initializer
        // (HashMap iteration order is not guaranteed, but at least one tensor should be non-F32)
        let has_bf16 = graph.tensors.iter().any(|t| t.dtype == DType::BF16);
        assert!(has_bf16, "at least one tensor should be BF16");
    }

